{
  "release_id": "release_001",
  "headline": "Release 001 brings dramatically faster dashboards, a simplified two-step signup flow, and clearer API docs — directly addressing the top themes from customer feedback this cycle.",
  "themes": [
    {
      "theme_name": "performance",
      "user_facing_summary": "Dashboard loads are now up to 67% faster at the 95th percentile (from ~2.4s down to ~800ms), and workspace member listings are ~30% quicker for teams of 50 or more. Org-settings calls also benefit from a new caching layer that cuts typical load under normal workspace activity.",
      "supporting_changes": [
        "PERF-411: Reduce dashboard p95 latency from 2.4s to 800ms via DB call batching",
        "PERF-415: Add Redis caching layer to org-settings API",
        "PERF-422: Eliminate N+1 query in workspace member listing endpoint"
      ]
    },
    {
      "theme_name": "onboarding",
      "user_facing_summary": "Signing up now takes just two steps — enter your email, verify, then complete a single profile screen. Optional fields like avatar and team name appear after signup rather than blocking it, and a set of contextual tooltips on the first-run dashboard helps new users find the four metrics they care about most.",
      "supporting_changes": [
        "ONBOARD-201: Replace 5-step signup with email-first 2-step flow",
        "ONBOARD-205: Add inline tooltips on first-run dashboard for top 4 metrics",
        "ONBOARD-208: Defer non-essential profile fields to post-signup"
      ]
    }
  ],
  "notable_changes": [
    "Dashboard 95th-percentile response time reduced from ~2.4s to ~800ms — the top complaint in the Q2 NPS survey.",
